import csv
from io import StringIO


class Loader:
    def parse_row(self, line):
        parts = line.split(',')
        # BUG: int() can't parse whitespace / empty strings
        return {'id': int(parts[0]), 'age': int(parts[1])}

    def load_rows(self, text):
        rows = []
        for line in text.splitlines():
            if not line:
                continue
            rows.append(self.parse_row(line))
        return rows


def load_rows(text):
    return Loader().load_rows(text)


def main():
    text = '1,30\n2, \n3,25'
    rows = load_rows(text)
    print(rows)


if __name__ == '__main__':
    main()
